import React, { createContext, useContext, useState, useEffect } from 'react';
import { account } from '../appwriteConfig';
import { ID } from 'appwrite';
import { createProfile, getProfile, updateProfile as updateProfileInDb } from '../services/supabaseService';

const AuthContext = createContext();

export const useAuth = () => useContext(AuthContext);

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Check active sessions
    const getInitialSession = async () => {
      try {
        const currentUser = await account.get();
        if (currentUser) {
          setUser(currentUser);
          const userProfile = await getProfile(currentUser.$id);
          setProfile(userProfile);
        }
      } catch (error) {
        console.error('Error getting session:', error);
      } finally {
        setLoading(false);
      }
    };

    getInitialSession();
  }, []);

  // Sign Up with Email
  const signUp = async (phone, password, userData) => {
    try {
      setLoading(true);
      const cleanPhone = phone.trim().replace(/\s/g, '');
      const dummyEmail = `${cleanPhone}@sabeel.com`;
      
      // 1. Create auth user
      const authData = await account.create(
        ID.unique(),
        dummyEmail,
        password,
        userData.name
      );

      // 2. Create session (login) right after signup
      await account.createEmailPasswordSession(dummyEmail, password);

      // 3. Create profile in database
      const { error: profileError } = await createProfile({
        id: authData.$id,
        email: dummyEmail,
        name: userData.name,
        phone: cleanPhone,
        grade: userData.grade,
        role: 'student',
        status: 'pending',
        avatar_url: userData.avatar_url || null
      });

      if (profileError) throw new Error(profileError);

      // 4. Update state variables manually since Appwrite doesn't have an onAuthStateChange listener
      setUser(authData);
      const newProfile = await getProfile(authData.$id);
      setProfile(newProfile);

      return { success: true, user: authData };
    } catch (error) {
      console.error('Sign up error:', error);
      return { success: false, error: error.message };
    } finally {
      setLoading(false);
    }
  };

  // Sign In with Phone
  const signIn = async (phone, password) => {
    try {
      setLoading(true);
      const cleanPhone = phone.trim().replace(/\s/g, '');
      const dummyEmail = `${cleanPhone}@sabeel.com`;
      
      await account.createEmailPasswordSession(dummyEmail, password);
      const currentUser = await account.get();

      const userProfile = await getProfile(currentUser.$id);
      
      setUser(currentUser);
      setProfile(userProfile);

      return { 
        success: true, 
        user: currentUser,
        profile: userProfile
      };
    } catch (error) {
      console.error('Sign in error:', error);
      return { success: false, error: error.message };
    } finally {
      setLoading(false);
    }
  };

  // Sign Out
  const signOut = async () => {
    try {
      setLoading(true);
      await account.deleteSession('current');
      
      setUser(null);
      setProfile(null);
      return { success: true };
    } catch (error) {
      console.error('Sign out error:', error);
      return { success: false, error: error.message };
    } finally {
      setLoading(false);
    }
  };

  // Reset Password
  const resetPassword = async (email) => {
    try {
      setLoading(true);
      await account.createRecovery(
        email,
        `${window.location.origin}/reset-password`
      );

      return { success: true };
    } catch (error) {
      console.error('Reset password error:', error);
      return { success: false, error: error.message };
    } finally {
      setLoading(false);
    }
  };

  // Update Profile
  const updateProfile = async (updates) => {
    try {
      if (!user) throw new Error('No user logged in');

      const { success, error } = await updateProfileInDb(user.$id, updates);

      if (!success) throw new Error(error);

      // Update local profile
      setProfile(prev => ({ ...prev, ...updates }));
      return { success: true };
    } catch (error) {
      console.error('Update profile error:', error);
      return { success: false, error: error.message };
    }
  };

  const value = {
    user,
    profile,
    loading,
    signUp,
    signIn,
    signOut,
    resetPassword,
    updateProfile
  };

  return (
    <AuthContext.Provider value={value}>
      {children}
    </AuthContext.Provider>
  );
};